        return True

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=object)
        self.initialize_board()

    def initialize_board(self):
        for i in range(3):
            for j in range(0, 8, 2):
                if (i + j) % 2 == 1:
                    self.board[i][j] = Piece()
        for i in range(5, 8):
            for j in range(0, 8, 2):
                if (i + j) % 2 == 1:
                    self.board[i][j] = Piece()

