from board import Board, Piece

class GameManager:
    def __init__(self):
        self.board = Board()
        self.current_player = 1

    def get_piece_at(self, row, col):
        return self.board.board[row][col]

    def is_valid_move(self, from_pos, to_pos):
        piece = self.get_piece_at(from_pos[0], from_pos[1])
        if piece and piece.__class__.__name__ == "Piece":
            # Simplified logic for validation
            return (abs(to_pos[0] - from_pos[0]) == 1 and abs(to_pos[1] - from_pos[1]) == 1)
        return False

    def make_move(self, from_pos, to_pos):
        if self.is_valid_move(from_pos, to_pos):
            piece = self.get_piece_at(from_pos[0], from_pos[1])
            self.board.board[from_pos[0]][from_pos[1]] = None
            self.board.board[to_pos[0]][to_pos[1]] = piece
            return True
        return False

    def switch_player(self):
        self.current_player = 2 if self.current_player == 1 else 1

# Example usage
if __name__ == "__main__":
    game_manager = GameManager()
    game_manager.board.print_board()
    from_pos = (0, 1)
    to_pos = (1, 2)
    if game_manager.make_move(from_pos, to_pos):
        print("Move made successfully!")
    else:
        print("Invalid move.")
    game_manager.switch_player()
    game_manager.board.print_board()
```

### main.py

