```python
from game_manager import GameManager

def get_user_input():
    return input("Enter move (e.g., 0,1-2,3): ").split("-")

def parse_move(move_str):
    from_pos, to_pos = map(lambda x: tuple(map(int, x.split(','))), move_str)
    return (from_pos[0], from_pos[1]), (to_pos[0], to_pos[1])

if __name__ == "__main__":
    game_manager = GameManager()
    while True:
        game_manager.board.print_board()
        move_str = "-".join(map(lambda x: f"{x[0]},{x[1]}", get_user_input()))
        from_pos, to_pos = parse_move(move_str)
        if game_manager.make_move(from_pos, to_pos):
            print("Move made successfully!")
        else:
            print("Invalid move.")
        game_manager.switch_player()
```

